"use client"

import { useForm } from "react-hook-form"
import { zodResolver } from "@hookform/resolvers/zod"
import * as z from "zod"
import { Button } from "@/components/ui/button"
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form"
import { Input } from "@/components/ui/input"
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover"
import { Calendar } from "@/components/ui/calendar"
import { CalendarIcon } from "lucide-react"
import { cn } from "@/lib/utils"
import { format } from "date-fns"
import { type Bill } from "@/types"

const formSchema = z.object({
  name: z.string().min(2, { message: "Bill name must be at least 2 characters." }),
  amount: z.coerce.number().positive({ message: "Amount must be positive." }),
  dueDate: z.date({ required_error: "A due date is required." }),
  isPaid: z.boolean().default(false),
  localReminder: z.boolean().default(false),
  emailReminder: z.boolean().default(false),
});

type BillFormValues = z.infer<typeof formSchema>;

interface BillFormProps {
    onSubmit: (data: BillFormValues) => void;
    bill: Bill | null;
    onClose: () => void;
}

export default function BillForm({ onSubmit, bill, onClose }: BillFormProps) {
  const form = useForm<BillFormValues>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      name: bill?.name || "",
      amount: bill?.amount || 0,
      dueDate: bill ? new Date(bill.dueDate) : new Date(),
      isPaid: bill?.isPaid || false,
      localReminder: bill?.localReminder || false,
      emailReminder: bill?.emailReminder || false,
    },
  });

  const handleSubmit = (values: BillFormValues) => {
    onSubmit(values);
  };

  return (
    <Form {...form}>
      <form onSubmit={form.handleSubmit(handleSubmit)} className="space-y-8">
        <FormField
          control={form.control}
          name="name"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Bill Name</FormLabel>
              <FormControl>
                <Input placeholder="e.g. Electricity Bill" {...field} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />
        <FormField
          control={form.control}
          name="amount"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Amount</FormLabel>
              <FormControl>
                <Input type="number" placeholder="e.g. 50.00" {...field} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />
        <FormField
          control={form.control}
          name="dueDate"
          render={({ field }) => (
            <FormItem className="flex flex-col">
              <FormLabel>Due Date</FormLabel>
              <Popover>
                <PopoverTrigger asChild>
                  <FormControl>
                    <Button
                      variant={"outline"}
                      className={cn(
                        "w-full pl-3 text-left font-normal",
                        !field.value && "text-muted-foreground"
                      )}
                    >
                      {field.value ? (
                        format(field.value, "PPP")
                      ) : (
                        <span>Pick a date</span>
                      )}
                      <CalendarIcon className="ml-auto h-4 w-4 opacity-50" />
                    </Button>
                  </FormControl>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0" align="start">
                  <Calendar
                    mode="single"
                    selected={field.value}
                    onSelect={field.onChange}
                    disabled={(date) => date < new Date("1900-01-01")}
                    initialFocus
                  />
                </PopoverContent>
              </Popover>
              <FormMessage />
            </FormItem>
          )}
        />
        <div className="flex justify-end gap-2">
            <Button type="button" variant="ghost" onClick={onClose}>Cancel</Button>
            <Button type="submit">{bill ? "Save Changes" : "Add Bill"}</Button>
        </div>
      </form>
    </Form>
  );
}
