"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { signOut } from "firebase/auth";
import { auth } from "@/lib/firebase";
import { useBills } from "@/hooks/use-bills";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuLabel, DropdownMenuSeparator, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { PlusCircle, WalletCards, User, LogOut, LockKeyhole } from "lucide-react";
import { type Bill } from "@/types";
import BillCard from "@/components/dashboard/bill-card";
import BillForm from "@/components/dashboard/bill-form";
import FastLoginSetupDialog from "@/components/dashboard/fast-login-dialog";
import { Toaster } from "@/components/ui/toaster";

export default function DashboardPageClient() {
  const { bills, addBill, updateBill, deleteBill } = useBills();
  const [user, setUser] = useState<any>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isFastLoginOpen, setIsFastLoginOpen] = useState(false);
  const [editingBill, setEditingBill] = useState<Bill | null>(null);
  const router = useRouter();
  
  useEffect(() => {
    const userData = localStorage.getItem("bill_tracker_user");
    if (userData) {
      setUser(JSON.parse(userData));
    }

    const unsubscribe = auth.onAuthStateChanged((firebaseUser) => {
      if (firebaseUser) {
        if (!userData || JSON.parse(userData).uid !== firebaseUser.uid) {
            localStorage.setItem("bill_tracker_user", JSON.stringify(firebaseUser));
            setUser(firebaseUser);
        }
      }
    });

    return () => unsubscribe();
  }, []);

  const handleLogout = async () => {
    await signOut(auth);
    localStorage.removeItem("bill_tracker_user");
    localStorage.removeItem("bill_tracker_pin"); // Also clear PIN on logout
    router.push("/?cleared=true");
  };

  const handleOpenForm = (bill: Bill | null = null) => {
    setEditingBill(bill);
    setIsFormOpen(true);
  };

  const handleFormSubmit = (data: Omit<Bill, 'id'>) => {
    if (editingBill) {
      updateBill({ ...editingBill, ...data });
    } else {
      addBill(data);
    }
    setIsFormOpen(false);
    setEditingBill(null);
  };
  
  const getInitials = (name: string | null | undefined) => {
    if (!name) return 'G';
    const names = name.split(' ');
    if (names.length > 1) {
      return names[0][0] + names[names.length - 1][0];
    }
    return name[0];
  }

  return (
    <div className="flex min-h-screen w-full flex-col bg-background">
      <header className="sticky top-0 flex h-16 items-center gap-4 border-b bg-card px-4 md:px-6 z-10">
        <nav className="flex-col gap-6 text-lg font-medium md:flex md:flex-row md:items-center md:gap-5 md:text-sm lg:gap-6 w-full">
          <a href="#" className="flex items-center gap-2 text-lg font-semibold md:text-base">
            <WalletCards className="h-6 w-6 text-primary" />
            <span className="sr-only">Offline Bill Boss</span>
            <span className="font-bold">Offline Bill Boss</span>
          </a>
        </nav>
        <div className="flex items-center gap-4 md:ml-auto md:gap-2 lg:gap-4">
          <Dialog open={isFormOpen} onOpenChange={setIsFormOpen}>
            <DialogTrigger asChild>
              <Button size="sm" className="gap-1">
                <PlusCircle className="h-4 w-4" />
                Add Bill
              </Button>
            </DialogTrigger>
            <DialogContent>
              <DialogHeader>
                <DialogTitle>{editingBill ? "Edit Bill" : "Add a New Bill"}</DialogTitle>
              </DialogHeader>
              <BillForm 
                onSubmit={handleFormSubmit}
                bill={editingBill}
                onClose={() => setIsFormOpen(false)}
              />
            </DialogContent>
          </Dialog>

          <FastLoginSetupDialog open={isFastLoginOpen} onOpenChange={setIsFastLoginOpen}/>
          
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="secondary" size="icon" className="rounded-full">
                <Avatar>
                  <AvatarImage src={user?.photoURL} alt={user?.displayName ?? 'User'} />
                  <AvatarFallback>{getInitials(user?.displayName)}</AvatarFallback>
                </Avatar>
                <span className="sr-only">Toggle user menu</span>
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end">
              <DropdownMenuLabel>{user ? user.displayName : 'Guest'}</DropdownMenuLabel>
              <DropdownMenuSeparator />
              <DropdownMenuItem onClick={() => setIsFastLoginOpen(true)}>
                <LockKeyhole className="mr-2 h-4 w-4" />
                <span>Fast Login Setup</span>
              </DropdownMenuItem>
              {user && (
                 <DropdownMenuItem onClick={handleLogout}>
                    <LogOut className="mr-2 h-4 w-4" />
                    <span>Logout</span>
                 </DropdownMenuItem>
              )}
               {!user && (
                 <DropdownMenuItem onClick={() => router.push('/')}>
                    <User className="mr-2 h-4 w-4" />
                    <span>Login</span>
                 </DropdownMenuItem>
              )}
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
      </header>
      <main className="flex flex-1 flex-col gap-4 p-4 md:gap-8 md:p-8">
        {bills.length > 0 ? (
          <div className="grid gap-4 md:gap-8 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
            {bills.map((bill) => (
              <BillCard
                key={bill.id}
                bill={bill}
                onEdit={() => handleOpenForm(bill)}
                onDelete={() => deleteBill(bill.id)}
                onStatusChange={(isPaid) => updateBill({ ...bill, isPaid })}
                onReminderChange={(type, value) => updateBill({...bill, [type]: value})}
              />
            ))}
          </div>
        ) : (
          <div className="flex flex-1 items-center justify-center rounded-lg border border-dashed shadow-sm">
            <Card className="w-full max-w-md text-center bg-transparent border-0 shadow-none">
                <CardContent className="p-6">
                    <h3 className="text-2xl font-semibold">No bills yet!</h3>
                    <p className="text-muted-foreground mt-2">Add your first bill to get started.</p>
                    <Button className="mt-4" onClick={() => handleOpenForm(null)}>
                        <PlusCircle className="mr-2 h-4 w-4"/>
                        Add Bill
                    </Button>
                </CardContent>
            </Card>
          </div>
        )}
      </main>
      <Toaster />
    </div>
  );
}
