"use client";

import { useState } from 'react';
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogFooter, DialogClose } from "@/components/ui/dialog";
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Fingerprint, LockKeyhole } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';

interface FastLoginSetupDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
}

export default function FastLoginSetupDialog({ open, onOpenChange }: FastLoginSetupDialogProps) {
    const [step, setStep] = useState<'initial' | 'pin'>('initial');
    const [pin, setPin] = useState('');
    const [confirmPin, setConfirmPin] = useState('');
    const [error, setError] = useState('');
    const { toast } = useToast();

    const handleSetPin = () => {
        setError('');
        if (pin.length < 4) {
            setError('PIN must be at least 4 digits.');
            return;
        }
        if (pin !== confirmPin) {
            setError('PINs do not match.');
            return;
        }
        localStorage.setItem('bill_tracker_pin', pin);
        toast({
            title: 'PIN Set!',
            description: 'You can now use your PIN for fast login.'
        });
        resetAndClose();
    };
    
    const handleBiometric = () => {
        toast({
            title: 'Feature Coming Soon',
            description: 'Biometric login will be available in the native mobile app.'
        });
    }

    const resetAndClose = () => {
        setStep('initial');
        setPin('');
        setConfirmPin('');
        setError('');
        onOpenChange(false);
    }

    return (
        <Dialog open={open} onOpenChange={(isOpen) => { if(!isOpen) resetAndClose(); else onOpenChange(true); }}>
            <DialogContent>
                {step === 'initial' && (
                    <>
                        <DialogHeader>
                            <DialogTitle>Fast Login Setup</DialogTitle>
                            <DialogDescription>
                                Secure your app with a PIN or Biometrics for quicker access.
                            </DialogDescription>
                        </DialogHeader>
                        <div className="grid gap-4 py-4">
                            <Button variant="outline" onClick={() => setStep('pin')}>
                                <LockKeyhole className="mr-2 h-4 w-4" /> Set a PIN
                            </Button>
                            <Button variant="outline" onClick={handleBiometric}>
                                <Fingerprint className="mr-2 h-4 w-4" /> Use Biometric
                            </Button>
                        </div>
                        <DialogFooter>
                            <Button variant="ghost" onClick={resetAndClose}>Skip For Now</Button>
                        </DialogFooter>
                    </>
                )}
                {step === 'pin' && (
                    <>
                        <DialogHeader>
                            <DialogTitle>Set Your PIN</DialogTitle>
                            <DialogDescription>
                                Create a 4-digit PIN for quick and secure access.
                            </DialogDescription>
                        </DialogHeader>
                        <div className="grid gap-4 py-4">
                            <div className="grid gap-2">
                                <Label htmlFor="pin">New PIN</Label>
                                <Input id="pin" type="password" value={pin} onChange={(e) => setPin(e.target.value)} maxLength={4} />
                            </div>
                            <div className="grid gap-2">
                                <Label htmlFor="confirm-pin">Confirm PIN</Label>
                                <Input id="confirm-pin" type="password" value={confirmPin} onChange={(e) => setConfirmPin(e.target.value)} maxLength={4}/>
                            </div>
                            {error && <p className="text-sm text-destructive">{error}</p>}
                        </div>
                        <DialogFooter>
                            <Button variant="ghost" onClick={() => setStep('initial')}>Back</Button>
                            <Button onClick={handleSetPin}>Set PIN</Button>
                        </DialogFooter>
                    </>
                )}
            </DialogContent>
        </Dialog>
    );
}
